"use client";

import { useBabelStore, type ViewName } from "@/lib/store";
import { HexBackground } from "@/components/babel/hex-bg";
import { Navigation } from "@/components/babel/navigation";
import { Landing } from "@/components/babel/landing";
import { SearchView } from "@/components/babel/search";
import { TicketsView } from "@/components/babel/tickets";
import { PageView } from "@/components/babel/page-view";
import { BrowseView } from "@/components/babel/browse";
import { AboutView } from "@/components/babel/about";
import { useEffect } from "react";
import { ALG, VERSION } from "@/lib/babel";

function ViewRenderer({ view }: { view: ViewName }) {
  switch (view) {
    case "landing":
      return <Landing />;
    case "search":
      return <SearchView />;
    case "tickets":
      return <TicketsView />;
    case "page":
      return <PageView />;
    case "browse":
      return <BrowseView />;
    case "about":
      return <AboutView />;
    default:
      return <Landing />;
  }
}

export default function Home() {
  const view = useBabelStore((s) => s.view);

  // Update document title based on view
  useEffect(() => {
    const titles: Record<ViewName, string> = {
      landing: "Русская Библиотека Вавилона",
      search: "Поиск — Русская Библиотека Вавилона",
      tickets: "Билеты — Русская Библиотека Вавилона",
      page: "Страница — Русская Библиотека Вавилона",
      browse: "Навигация — Русская Библиотека Вавилона",
      about: "О проекте — Русская Библиотека Вавилона",
    };
    document.title = titles[view] || titles.landing;
  }, [view]);

  // Handle keyboard navigation
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        useBabelStore.getState().setView("landing");
      }
    };
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, []);

  return (
    <div className="babel-bg min-h-screen flex flex-col">
      {/* Animated hex background */}
      <HexBackground />

      {/* Navigation header */}
      <Navigation />

      {/* Main content */}
      <main className="flex-1">
        <ViewRenderer view={view} />
      </main>

      {/* Footer */}
      <footer className="relative z-10 mt-auto px-4 py-4 flex flex-wrap items-center justify-center gap-3 text-xs text-muted-foreground/50">
        <span>
          Алгоритм: <code className="text-[var(--gold)]/60">{VERSION}</code>
        </span>
        <span>·</span>
        <span>
          <code className="text-[var(--gold)]/60">
            координаты ⇄ BigInt ⇄ текст
          </code>
        </span>
        <span>·</span>
        <span>Страницы не хранятся</span>
      </footer>
    </div>
  );
}
