import { create } from "zustand";
import {
  Coordinates,
  VariantType,
  numberToCoordinates,
  coordinatesToNumber,
  textToNumber,
  numberToText,
  numberToB64,
  makePageWithPhrase,
  strategyFromVariantType,
  randomPageText,
  maxPageNumber,
  paragraphize,
  snippetByRange,
  prettyBase36,
  coordinateTitle,
  ALG,
} from "@/lib/babel";

// --- View types ---

export type ViewName =
  | "landing"
  | "search"
  | "tickets"
  | "page"
  | "browse"
  | "about";

export interface HighlightRange {
  start: number;
  length: number;
}

// --- Store state ---

interface BabelState {
  // Navigation
  view: ViewName;
  setView: (v: ViewName) => void;

  // Page view
  currentPageNumber: bigint | null;
  currentHighlight: HighlightRange | null;
  openPage: (n: bigint, hl?: HighlightRange | null) => void;
  openCoordinates: (c: Coordinates, hl?: HighlightRange | null) => void;

  // Search
  searchPhrase: string;
  setSearchPhrase: (p: string) => void;
  searchVariantType: VariantType;
  setSearchVariantType: (t: VariantType) => void;
  searchPosition: "center" | "start" | "end" | "random";
  setSearchPosition: (p: "center" | "start" | "end" | "random") => void;
  searchCount: number;
  setSearchCount: (n: number) => void;
  searchOffset: number;
  setSearchOffset: (n: number) => void;
  searchResults: SearchResult[];
  searchError: string | null;
  performSearch: () => void;
  nextBatch: () => void;

  // Browse
  browseCoordinates: Coordinates | null;
  browseLevel: "hall" | "wall" | "shelf" | "volume" | null;
  openBrowse: (c: Coordinates, level: "hall" | "wall" | "shelf" | "volume") => void;

  // Tickets
  ticketPages: TicketPage[];
  currentTicketIndex: number;
  generateTickets: (count?: number) => void;
  nextTicket: () => void;
  prevTicket: () => void;
  goToTicket: (index: number) => void;

  // Favorites
  favorites: Array<Record<string, string>>;
  loadFavorites: () => void;
  addFavorite: (item: Record<string, string>) => void;
  removeFavorite: (index: number) => void;
}

export interface SearchResult {
  phrase: string;
  variant: number;
  position: number;
  text: string;
  number: bigint;
  coordinates: Coordinates;
  b64: string;
  b36: string;
  snippet: string;
}

export interface TicketPage {
  number: bigint;
  coordinates: Coordinates;
  text: string;
  b64: string;
  title: string;
}

export const useBabelStore = create<BabelState>((set, get) => ({
  // Navigation
  view: "landing",
  setView: (v) => set({ view: v }),

  // Page view
  currentPageNumber: null,
  currentHighlight: null,
  openPage: (n, hl = null) => {
    set({
      view: "page",
      currentPageNumber: n,
      currentHighlight: hl,
    });
  },
  openCoordinates: (c, hl = null) => {
    const n = coordinatesToNumber(c);
    set({
      view: "page",
      currentPageNumber: n,
      currentHighlight: hl,
    });
  },

  // Search
  searchPhrase: "",
  setSearchPhrase: (p) => set({ searchPhrase: p }),
  searchVariantType: "chaos",
  setSearchVariantType: (t) => set({ searchVariantType: t }),
  searchPosition: "random",
  setSearchPosition: (p) => set({ searchPosition: p }),
  searchCount: 8,
  setSearchCount: (n) => set({ searchCount: n }),
  searchOffset: 0,
  setSearchOffset: (n) => set({ searchOffset: n }),
  searchResults: [],
  searchError: null,
  performSearch: () => {
    const state = get();
    const { searchPhrase, searchVariantType, searchPosition, searchCount, searchOffset } = state;

    try {
      const strategy = strategyFromVariantType(searchVariantType, searchPosition);
      const results: SearchResult[] = [];

      for (let i = 1; i <= searchCount; i++) {
        const page = makePageWithPhrase(searchPhrase, i, strategy, searchOffset);
        const n = textToNumber(page.text);
        const c = numberToCoordinates(n);
        const range = { start: page.position, length: page.phrase.length };
        const snippet = snippetByRange(page.text, range);
        results.push({
          phrase: page.phrase,
          variant: page.variant,
          position: page.position,
          text: page.text,
          number: n,
          coordinates: c,
          b64: numberToB64(n),
          b36: prettyBase36(n),
          snippet,
        });
      }

      set({ searchResults: results, searchError: null, view: "search" });
    } catch (err) {
      set({
        searchError: err instanceof Error ? err.message : "Ошибка поиска",
        searchResults: [],
      });
    }
  },
  nextBatch: () => {
    const state = get();
    const newOffset = state.searchOffset + state.searchCount;
    set({ searchOffset: newOffset });
    // Re-run search with new offset
    const { searchPhrase, searchVariantType, searchPosition, searchCount } = state;
    try {
      const strategy = strategyFromVariantType(searchVariantType, searchPosition);
      const results: SearchResult[] = [];
      for (let i = 1; i <= searchCount; i++) {
        const page = makePageWithPhrase(searchPhrase, i, strategy, newOffset);
        const n = textToNumber(page.text);
        const c = numberToCoordinates(n);
        const range = { start: page.position, length: page.phrase.length };
        const snippet = snippetByRange(page.text, range);
        results.push({
          phrase: page.phrase,
          variant: page.variant,
          position: page.position,
          text: page.text,
          number: n,
          coordinates: c,
          b64: numberToB64(n),
          b36: prettyBase36(n),
          snippet,
        });
      }
      set({ searchResults: results, searchError: null });
    } catch (err) {
      set({
        searchError: err instanceof Error ? err.message : "Ошибка поиска",
        searchResults: [],
      });
    }
  },

  // Browse
  browseCoordinates: null,
  browseLevel: null,
  openBrowse: (c, level) => set({ view: "browse", browseCoordinates: c, browseLevel: level }),

  // Tickets
  ticketPages: [],
  currentTicketIndex: 0,
  generateTickets: (count = 6) => {
    const pages: TicketPage[] = [];
    for (let i = 0; i < count; i++) {
      const text = randomPageText();
      const n = textToNumber(text);
      const c = numberToCoordinates(n);
      pages.push({
        number: n,
        coordinates: c,
        text,
        b64: numberToB64(n),
        title: coordinateTitle(c),
      });
    }
    set({ ticketPages: pages, currentTicketIndex: 0, view: "tickets" });
  },
  nextTicket: () => {
    const { currentTicketIndex, ticketPages } = get();
    if (currentTicketIndex < ticketPages.length - 1) {
      set({ currentTicketIndex: currentTicketIndex + 1 });
    }
  },
  prevTicket: () => {
    const { currentTicketIndex } = get();
    if (currentTicketIndex > 0) {
      set({ currentTicketIndex: currentTicketIndex - 1 });
    }
  },
  goToTicket: (index) => set({ currentTicketIndex: index }),

  // Favorites
  favorites: [],
  loadFavorites: () => {
    try {
      const items = JSON.parse(localStorage.getItem("babelFavorites") || "[]");
      set({ favorites: items });
    } catch {
      set({ favorites: [] });
    }
  },
  addFavorite: (item) => {
    const { favorites } = get();
    const key = item.n || item.url;
    const filtered = favorites.filter((x) => (x.n || x.url) !== key);
    const updated = [{ ...item, createdAt: new Date().toISOString() }, ...filtered].slice(0, 120);
    set({ favorites: updated });
    localStorage.setItem("babelFavorites", JSON.stringify(updated));
  },
  removeFavorite: (index) => {
    const { favorites } = get();
    const updated = [...favorites];
    updated.splice(index, 1);
    set({ favorites: updated });
    localStorage.setItem("babelFavorites", JSON.stringify(updated));
  },
}));
