"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useBabelStore, type TicketPage } from "@/lib/store";
import {
  coordinateTitleShort,
  shortNumber,
  paragraphize,
  randomPageText,
  ALG,
} from "@/lib/babel";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  ChevronLeft,
  ChevronRight,
  Shuffle,
  FlipHorizontal,
  BookOpen,
  Copy,
  BookmarkPlus,
  Library,
} from "lucide-react";
import { toast } from "sonner";

export function TicketsView() {
  const {
    ticketPages,
    currentTicketIndex,
    nextTicket,
    prevTicket,
    goToTicket,
    generateTickets,
    openPage,
    addFavorite,
    openBrowse,
  } = useBabelStore();

  const [flippedCards, setFlippedCards] = useState<Set<number>>(new Set());
  const [fullPageView, setFullPageView] = useState<number | null>(null);

  if (ticketPages.length === 0) {
    return (
      <div className="relative z-10 max-w-4xl mx-auto px-4 py-6 text-center">
        <p className="text-muted-foreground mb-4">Нет билетов. Создайте новые.</p>
        <Button
          onClick={() => generateTickets(6)}
          className="bg-[rgba(222,192,125,0.2)] text-[var(--gold-bright)] border border-[rgba(222,192,125,0.48)]"
        >
          <Shuffle className="h-4 w-4 mr-2" />
          Создать билеты
        </Button>
      </div>
    );
  }

  const currentTicket = ticketPages[currentTicketIndex];
  const isFlipped = flippedCards.has(currentTicketIndex);

  const toggleFlip = (idx: number) => {
    setFlippedCards((prev) => {
      const next = new Set(prev);
      if (next.has(idx)) next.delete(idx);
      else next.add(idx);
      return next;
    });
  };

  const handleOpenPage = () => {
    if (currentTicket) {
      openPage(currentTicket.number);
    }
  };

  const handleCopyB64 = () => {
    if (currentTicket) {
      navigator.clipboard.writeText(currentTicket.b64);
      toast.success("base64url скопирован");
    }
  };

  const handleSaveFavorite = () => {
    if (currentTicket) {
      addFavorite({
        title: currentTicket.title,
        n: currentTicket.number.toString(),
        type: "page",
      });
      toast.success("Сохранено в избранное");
    }
  };

  const handleBrowse = () => {
    if (currentTicket) {
      openBrowse(currentTicket.coordinates, "volume");
    }
  };

  const handleRandomize = () => {
    generateTickets(6);
    setFlippedCards(new Set());
  };

  return (
    <div className="relative z-10 max-w-4xl mx-auto px-4 py-6">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className="text-2xl sm:text-3xl font-bold text-[var(--gold-bright)]">
              Билеты
            </h1>
            <p className="text-muted-foreground text-sm">
              Случайные страницы из библиотеки
            </p>
          </div>
          <div className="flex gap-2">
            <Button
              variant="ghost"
              size="sm"
              onClick={handleRandomize}
              className="text-muted-foreground hover:text-foreground"
            >
              <Shuffle className="h-4 w-4" />
            </Button>
          </div>
        </div>

        {/* Main ticket card */}
        <AnimatePresence mode="wait">
          <motion.div
            key={currentTicketIndex}
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -30 }}
            transition={{ duration: 0.3 }}
          >
            <div
              className="babel-card gold-border-glow overflow-hidden"
              style={{ perspective: "1000px" }}
            >
              {/* Ticket header with hex decoration */}
              <div className="relative bg-gradient-to-r from-[rgba(222,192,125,0.12)] to-[rgba(222,192,125,0.04)] border-b border-border p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-[var(--gold-bright)] font-semibold text-lg">
                      Билет {currentTicketIndex + 1}
                    </p>
                    <p className="text-muted-foreground text-xs">
                      из {ticketPages.length}
                    </p>
                  </div>
                  <div className="flex gap-2">
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => toggleFlip(currentTicketIndex)}
                      className="text-[var(--gold)] hover:text-[var(--gold-bright)]"
                    >
                      <FlipHorizontal className="h-4 w-4" />
                    </Button>
                  </div>
                </div>

                {/* Decorative hex pattern */}
                <div className="absolute right-4 top-1/2 -translate-y-1/2 opacity-10">
                  <svg width="60" height="52" viewBox="0 0 60 52">
                    <polygon
                      points="30,1 58,14 58,38 30,51 2,38 2,14"
                      fill="none"
                      stroke="var(--gold)"
                      strokeWidth="1"
                    />
                  </svg>
                </div>
              </div>

              {/* Card content */}
              <div className="p-5">
                {!isFlipped ? (
                  /* Front: Preview */
                  <TicketFront
                    ticket={currentTicket}
                    onOpen={handleOpenPage}
                  />
                ) : (
                  /* Back: Full page text */
                  <TicketBack ticket={currentTicket} />
                )}
              </div>

              {/* Coordinates bar */}
              <div className="border-t border-border p-4">
                <div className="flex flex-wrap gap-1.5 mb-3">
                  {[
                    { label: "Сектор", value: shortNumber(currentTicket.coordinates.sector) },
                    { label: "Зал", value: String(currentTicket.coordinates.hall) },
                    { label: "Стена", value: String(currentTicket.coordinates.wall) },
                    { label: "Полка", value: String(currentTicket.coordinates.shelf) },
                    { label: "Том", value: String(currentTicket.coordinates.volume) },
                    { label: "Лист", value: String(currentTicket.coordinates.page) },
                  ].map((item) => (
                    <span
                      key={item.label}
                      className="inline-flex items-center rounded-lg border border-[rgba(255,255,255,0.12)] bg-[rgba(0,0,0,0.22)] px-2 py-1 text-xs"
                    >
                      <span className="text-[var(--gold)] mono-text mr-1">{item.value}</span>
                      <span className="text-muted-foreground">{item.label}</span>
                    </span>
                  ))}
                </div>

                {/* Action buttons */}
                <div className="flex flex-wrap gap-2">
                  <Button
                    size="sm"
                    onClick={handleOpenPage}
                    className="bg-[rgba(222,192,125,0.2)] text-[var(--gold-bright)] border border-[rgba(222,192,125,0.48)] hover:bg-[rgba(222,192,125,0.3)]"
                  >
                    <BookOpen className="h-3.5 w-3.5 mr-1.5" />
                    Открыть
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={handleCopyB64}
                    className="text-muted-foreground hover:text-foreground"
                  >
                    <Copy className="h-3.5 w-3.5 mr-1" />
                    Копировать
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={handleSaveFavorite}
                    className="text-muted-foreground hover:text-foreground"
                  >
                    <BookmarkPlus className="h-3.5 w-3.5 mr-1" />
                    В избранное
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={handleBrowse}
                    className="text-muted-foreground hover:text-foreground"
                  >
                    <Library className="h-3.5 w-3.5 mr-1" />
                    Том
                  </Button>
                </div>
              </div>
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Navigation */}
        <div className="flex items-center justify-center gap-4 mt-6">
          <Button
            variant="ghost"
            size="sm"
            onClick={prevTicket}
            disabled={currentTicketIndex === 0}
            className="text-muted-foreground hover:text-foreground disabled:opacity-30"
          >
            <ChevronLeft className="h-5 w-5" />
          </Button>

          <div className="flex gap-1.5">
            {ticketPages.map((_, idx) => (
              <button
                key={idx}
                onClick={() => goToTicket(idx)}
                className={`w-2.5 h-2.5 rounded-full transition-all cursor-pointer ${
                  idx === currentTicketIndex
                    ? "bg-[var(--gold)] scale-125"
                    : "bg-[rgba(255,255,255,0.15)] hover:bg-[rgba(255,255,255,0.3)]"
                }`}
              />
            ))}
          </div>

          <Button
            variant="ghost"
            size="sm"
            onClick={nextTicket}
            disabled={currentTicketIndex === ticketPages.length - 1}
            className="text-muted-foreground hover:text-foreground disabled:opacity-30"
          >
            <ChevronRight className="h-5 w-5" />
          </Button>
        </div>
      </motion.div>
    </div>
  );
}

function TicketFront({
  ticket,
  onOpen,
}: {
  ticket: TicketPage;
  onOpen: () => void;
}) {
  const c = ticket.coordinates;
  // Show first few lines as preview
  const lines = paragraphize(ticket.text).split("\n").slice(0, 6);

  return (
    <div>
      <h3 className="text-[var(--gold-bright)] font-semibold text-lg mb-1">
        {coordinateTitleShort(c)}
      </h3>
      <p className="text-xs text-muted-foreground mb-4">
        Сектор {shortNumber(c.sector)} · Зал {c.hall}
      </p>

      {/* Page preview */}
      <div className="page-text text-xs !p-4 !rounded-xl max-h-52 overflow-hidden relative">
        {lines.map((line, i) => (
          <div key={i} className="leading-relaxed">
            {line}
          </div>
        ))}
        <div className="absolute bottom-0 left-0 right-0 h-16 bg-gradient-to-t from-[rgba(0,0,0,0.8)] to-transparent" />
      </div>

      <div className="flex gap-2 mt-3">
        <Badge
          variant="outline"
          className="border-border text-muted-foreground text-xs"
        >
          ru1
        </Badge>
        <Badge
          variant="outline"
          className="border-border text-muted-foreground text-xs"
        >
          {ALG.pageLength} символов
        </Badge>
        <Badge
          variant="outline"
          className="border-border text-muted-foreground text-xs"
        >
          алфавит {ALG.alphabet.length}
        </Badge>
      </div>
    </div>
  );
}

function TicketBack({ ticket }: { ticket: TicketPage }) {
  const para = paragraphize(ticket.text);

  return (
    <div>
      <h3 className="text-[var(--gold-bright)] font-semibold mb-3">
        Полный текст страницы
      </h3>
      <div className="page-text text-xs !p-3 !rounded-xl max-h-96 overflow-y-auto custom-scroll">
        {para}
      </div>
    </div>
  );
}
