"use client";

import { useBabelStore, type ViewName } from "@/lib/store";
import { Button } from "@/components/ui/button";
import {
  BookOpen,
  Search,
  Ticket,
  Library,
  Info,
  Home,
  Shuffle,
  Star,
} from "lucide-react";
import { randomPageText, textToNumber, numberToCoordinates, numberToB64, coordinateTitle } from "@/lib/babel";
import { toast } from "sonner";
import { useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

export function Navigation() {
  const { view, setView, openPage, favorites, loadFavorites, generateTickets } = useBabelStore();
  const [showFavorites, setShowFavorites] = useState(false);

  const navItems: Array<{
    id: ViewName;
    label: string;
    icon: React.ReactNode;
  }> = [
    { id: "landing", label: "Главная", icon: <Home className="h-4 w-4" /> },
    { id: "search", label: "Поиск", icon: <Search className="h-4 w-4" /> },
    { id: "tickets", label: "Билеты", icon: <Ticket className="h-4 w-4" /> },
    { id: "browse", label: "Навигация", icon: <Library className="h-4 w-4" /> },
    { id: "about", label: "О проекте", icon: <Info className="h-4 w-4" /> },
  ];

  const handleRandomPage = () => {
    const text = randomPageText();
    const n = textToNumber(text);
    openPage(n);
    toast.success("Случайная страница открыта");
  };

  const handleFavorites = () => {
    loadFavorites();
    setShowFavorites(true);
  };

  return (
    <>
      <header className="relative z-10 flex items-center justify-between gap-4 px-4 py-3 sm:px-6">
        <button
          onClick={() => setView("landing")}
          className="flex items-center gap-3 group cursor-pointer"
        >
          <span className="flex h-10 w-10 items-center justify-center rounded-xl border border-[rgba(222,192,125,0.35)] bg-gradient-to-br from-[rgba(222,192,125,0.19)] to-[rgba(255,255,255,0.04)] font-black text-[var(--gold)] text-sm">
            БВ
          </span>
          <span className="hidden sm:block">
            <strong className="block text-sm tracking-tight text-foreground">
              Русская Библиотека Вавилона
            </strong>
            <small className="block text-xs text-muted-foreground">
              координаты · base64url · ru1
            </small>
          </span>
        </button>

        <nav className="flex items-center gap-1 sm:gap-2">
          {navItems.map((item) => (
            <Button
              key={item.id}
              variant={view === item.id ? "default" : "ghost"}
              size="sm"
              onClick={() => {
                if (item.id === "tickets") {
                  generateTickets(6);
                } else {
                  setView(item.id);
                }
              }}
              className={
                view === item.id
                  ? "bg-[rgba(222,192,125,0.16)] text-[var(--gold-bright)] border-[rgba(222,192,125,0.48)] hover:bg-[rgba(222,192,125,0.24)]"
                  : "text-muted-foreground hover:text-foreground hover:bg-[rgba(255,255,255,0.08)]"
              }
            >
              {item.icon}
              <span className="hidden md:inline ml-1.5">{item.label}</span>
            </Button>
          ))}
          <div className="w-px h-6 bg-border mx-1 hidden sm:block" />
          <Button
            variant="ghost"
            size="sm"
            onClick={handleRandomPage}
            className="text-muted-foreground hover:text-foreground hover:bg-[rgba(255,255,255,0.08)]"
          >
            <Shuffle className="h-4 w-4" />
            <span className="hidden lg:inline ml-1.5">Случайная</span>
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleFavorites}
            className="text-muted-foreground hover:text-foreground hover:bg-[rgba(255,255,255,0.08)]"
          >
            <Star className="h-4 w-4" />
          </Button>
        </nav>
      </header>

      {/* Favorites Dialog */}
      <Dialog open={showFavorites} onOpenChange={setShowFavorites}>
        <DialogContent className="bg-[#0d0e14] border-border max-h-[80vh] overflow-y-auto custom-scroll">
          <DialogHeader>
            <DialogTitle className="text-[var(--gold-bright)]">Избранное</DialogTitle>
          </DialogHeader>
          {favorites.length === 0 ? (
            <p className="text-muted-foreground text-sm py-4">Пока пусто. Сохраняйте страницы и находки.</p>
          ) : (
            <div className="space-y-3">
              {favorites.map((item, idx) => (
                <div
                  key={idx}
                  className="flex items-start justify-between gap-3 rounded-xl border border-border bg-[rgba(0,0,0,0.2)] p-3"
                >
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-foreground truncate">
                      {item.title || item.type}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {item.type} · {item.createdAt ? new Date(item.createdAt).toLocaleString("ru") : ""}
                    </p>
                  </div>
                  <div className="flex gap-2 shrink-0">
                    {item.n && (
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => {
                          const n = BigInt(item.n!);
                          openPage(n);
                          setShowFavorites(false);
                        }}
                        className="text-[var(--gold)] hover:text-[var(--gold-bright)]"
                      >
                        <BookOpen className="h-3 w-3" />
                      </Button>
                    )}
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => useBabelStore.getState().removeFavorite(idx)}
                      className="text-destructive hover:text-red-400"
                    >
                      ×
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}
