"use client";

import { useEffect, useRef } from "react";

interface Hex {
  x: number;
  y: number;
  size: number;
  speed: number;
  opacity: number;
  rotation: number;
  rotSpeed: number;
}

interface Particle {
  x: number;
  y: number;
  size: number;
  speed: number;
  opacity: number;
  phase: number;
}

export function HexBackground() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animRef = useRef<number>(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;
    };
    resize();
    window.addEventListener("resize", resize);

    // Create hexagons
    const hexCount = Math.floor((width * height) / 80000);
    const hexes: Hex[] = Array.from({ length: Math.min(hexCount, 25) }, () => ({
      x: Math.random() * width,
      y: Math.random() * height,
      size: 20 + Math.random() * 60,
      speed: 0.15 + Math.random() * 0.3,
      opacity: 0.03 + Math.random() * 0.06,
      rotation: Math.random() * Math.PI * 2,
      rotSpeed: (Math.random() - 0.5) * 0.003,
    }));

    // Create particles
    const particles: Particle[] = Array.from({ length: 60 }, () => ({
      x: Math.random() * width,
      y: Math.random() * height,
      size: 0.5 + Math.random() * 1.5,
      speed: 0.1 + Math.random() * 0.2,
      opacity: Math.random(),
      phase: Math.random() * Math.PI * 2,
    }));

    function drawHex(
      cx: number,
      cy: number,
      size: number,
      rotation: number,
      opacity: number
    ) {
      if (!ctx) return;
      ctx.save();
      ctx.translate(cx, cy);
      ctx.rotate(rotation);
      ctx.beginPath();
      for (let i = 0; i < 6; i++) {
        const angle = (Math.PI / 3) * i - Math.PI / 6;
        const x = size * Math.cos(angle);
        const y = size * Math.sin(angle);
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      }
      ctx.closePath();
      ctx.strokeStyle = `rgba(222, 192, 125, ${opacity})`;
      ctx.lineWidth = 1;
      ctx.stroke();
      ctx.restore();
    }

    let time = 0;
    function animate() {
      if (!ctx) return;
      ctx.clearRect(0, 0, width, height);
      time += 0.01;

      // Draw connecting lines between nearby hexagons
      for (let i = 0; i < hexes.length; i++) {
        for (let j = i + 1; j < hexes.length; j++) {
          const dx = hexes[i].x - hexes[j].x;
          const dy = hexes[i].y - hexes[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 300) {
            const lineOpacity = (1 - dist / 300) * 0.04;
            ctx.beginPath();
            ctx.moveTo(hexes[i].x, hexes[i].y);
            ctx.lineTo(hexes[j].x, hexes[j].y);
            ctx.strokeStyle = `rgba(222, 192, 125, ${lineOpacity})`;
            ctx.lineWidth = 0.5;
            ctx.stroke();
          }
        }
      }

      // Draw and move hexagons
      for (const hex of hexes) {
        drawHex(hex.x, hex.y, hex.size, hex.rotation, hex.opacity);
        hex.y -= hex.speed;
        hex.rotation += hex.rotSpeed;
        if (hex.y < -hex.size * 2) {
          hex.y = height + hex.size * 2;
          hex.x = Math.random() * width;
        }
      }

      // Draw particles
      for (const p of particles) {
        const flickerOpacity = p.opacity * (0.3 + 0.7 * Math.sin(time * 2 + p.phase));
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(222, 192, 125, ${flickerOpacity * 0.5})`;
        ctx.fill();
        p.y -= p.speed;
        if (p.y < -10) {
          p.y = height + 10;
          p.x = Math.random() * width;
        }
      }

      animRef.current = requestAnimationFrame(animate);
    }

    animate();

    return () => {
      window.removeEventListener("resize", resize);
      cancelAnimationFrame(animRef.current);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 pointer-events-none"
      style={{ zIndex: 0 }}
      aria-hidden="true"
    />
  );
}
