"use client";

import { motion } from "framer-motion";
import { useBabelStore, type SearchResult } from "@/lib/store";
import { type VariantType, shortNumber, ALG } from "@/lib/babel";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Search, Zap, Cloud, BookOpen, ChevronRight, Copy, BookmarkPlus } from "lucide-react";
import { toast } from "sonner";

const VARIANT_TYPES: Array<{
  id: VariantType;
  label: string;
  description: string;
  icon: React.ReactNode;
}> = [
  {
    id: "emptiness",
    label: "Пустота",
    description: "Остальной текст — пробелы",
    icon: <Cloud className="h-4 w-4" />,
  },
  {
    id: "chaos",
    label: "Хаос",
    description: "Случайные символы",
    icon: <Zap className="h-4 w-4" />,
  },
  {
    id: "words",
    label: "Случайные слова",
    description: "Русские слова (~18% пробелов)",
    icon: <BookOpen className="h-4 w-4" />,
  },
];

const POSITION_OPTIONS = [
  { id: "random" as const, label: "Случайно" },
  { id: "center" as const, label: "По центру" },
  { id: "start" as const, label: "В начале" },
  { id: "end" as const, label: "В конце" },
];

export function SearchView() {
  const {
    searchPhrase,
    setSearchPhrase,
    searchVariantType,
    setSearchVariantType,
    searchPosition,
    setSearchPosition,
    searchCount,
    setSearchCount,
    searchOffset,
    searchResults,
    searchError,
    performSearch,
    nextBatch,
    openPage,
    addFavorite,
  } = useBabelStore();

  const handleSearch = () => {
    if (!searchPhrase.trim()) {
      toast.error("Введите фразу для поиска");
      return;
    }
    performSearch();
  };

  const handleCopyB64 = (b64: string) => {
    navigator.clipboard.writeText(b64);
    toast.success("base64url скопирован");
  };

  const handleSaveFavorite = (result: SearchResult) => {
    addFavorite({
      title: `Фраза: ${result.phrase}`,
      n: result.number.toString(),
      type: "find",
    });
    toast.success("Сохранено в избранное");
  };

  return (
    <div className="relative z-10 max-w-4xl mx-auto px-4 py-6">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h1 className="text-2xl sm:text-3xl font-bold text-[var(--gold-bright)] mb-2">
          Найти фразу
        </h1>
        <p className="text-muted-foreground text-sm mb-6">
          Фраза встраивается в полный лист, лист превращается в число, число
          раскладывается в координаты.
        </p>

        {/* Search Input */}
        <div className="babel-card p-5 mb-4">
          <Textarea
            placeholder="Введите фразу, например: каждая страница имеет свою ссылку"
            value={searchPhrase}
            onChange={(e) => setSearchPhrase(e.target.value)}
            className="min-h-[100px] bg-[rgba(0,0,0,0.25)] border-border text-foreground placeholder:text-muted-foreground/50 resize-y"
          />
        </div>

        {/* Variant Type Selector */}
        <div className="mb-4">
          <label className="block text-sm font-medium text-muted-foreground mb-3">
            Тип окружения
          </label>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            {VARIANT_TYPES.map((vt) => (
              <button
                key={vt.id}
                onClick={() => setSearchVariantType(vt.id)}
                className={`babel-card p-4 text-left transition-all duration-200 cursor-pointer ${
                  searchVariantType === vt.id
                    ? "border-[rgba(222,192,125,0.48)] bg-[rgba(222,192,125,0.1)] shadow-[0_0_20px_rgba(222,192,125,0.1)]"
                    : "hover:border-[rgba(222,192,125,0.25)]"
                }`}
              >
                <div className="flex items-center gap-2 mb-1">
                  <span
                    className={
                      searchVariantType === vt.id
                        ? "text-[var(--gold)]"
                        : "text-muted-foreground"
                    }
                  >
                    {vt.icon}
                  </span>
                  <span
                    className={`font-medium text-sm ${
                      searchVariantType === vt.id
                        ? "text-[var(--gold-bright)]"
                        : "text-foreground"
                    }`}
                  >
                    {vt.label}
                  </span>
                </div>
                <p className="text-xs text-muted-foreground">{vt.description}</p>
              </button>
            ))}
          </div>
        </div>

        {/* Position & Count */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
          <div>
            <label className="block text-sm font-medium text-muted-foreground mb-2">
              Расположение фразы
            </label>
            <div className="flex flex-wrap gap-2">
              {POSITION_OPTIONS.map((opt) => (
                <Button
                  key={opt.id}
                  variant={searchPosition === opt.id ? "default" : "ghost"}
                  size="sm"
                  onClick={() => setSearchPosition(opt.id)}
                  className={
                    searchPosition === opt.id
                      ? "bg-[rgba(222,192,125,0.16)] text-[var(--gold-bright)] border-[rgba(222,192,125,0.48)]"
                      : "text-muted-foreground hover:text-foreground"
                  }
                >
                  {opt.label}
                </Button>
              ))}
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-muted-foreground mb-2">
              Количество вариантов
            </label>
            <Input
              type="number"
              min={1}
              max={48}
              value={searchCount}
              onChange={(e) => setSearchCount(Math.max(1, Math.min(48, parseInt(e.target.value) || 1)))}
              className="bg-[rgba(0,0,0,0.25)] border-border"
            />
          </div>
          <div className="flex items-end">
            <Button
              onClick={handleSearch}
              className="w-full bg-[rgba(222,192,125,0.2)] text-[var(--gold-bright)] border border-[rgba(222,192,125,0.48)] hover:bg-[rgba(222,192,125,0.3)]"
            >
              <Search className="h-4 w-4 mr-2" />
              Найти
            </Button>
          </div>
        </div>

        {/* Error */}
        {searchError && (
          <div className="rounded-xl border border-red-500/30 bg-red-500/10 p-4 mb-4">
            <p className="text-red-300 text-sm">{searchError}</p>
          </div>
        )}

        {/* Results */}
        {searchResults.length > 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="space-y-4"
          >
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-semibold text-foreground">
                Результаты
              </h2>
              <Button
                variant="ghost"
                size="sm"
                onClick={nextBatch}
                className="text-[var(--gold)] hover:text-[var(--gold-bright)]"
              >
                Следующие варианты
                <ChevronRight className="h-4 w-4 ml-1" />
              </Button>
            </div>

            {searchResults.map((result, idx) => (
              <SearchResultCard
                key={idx}
                result={result}
                onOpen={() =>
                  openPage(result.number, {
                    start: result.position,
                    length: result.phrase.length,
                  })
                }
                onCopyB64={() => handleCopyB64(result.b64)}
                onSave={() => handleSaveFavorite(result)}
              />
            ))}
          </motion.div>
        )}
      </motion.div>
    </div>
  );
}

function SearchResultCard({
  result,
  onOpen,
  onCopyB64,
  onSave,
}: {
  result: SearchResult;
  onOpen: () => void;
  onCopyB64: () => void;
  onSave: () => void;
}) {
  const c = result.coordinates;

  // Highlight the phrase in the snippet
  const highlightSnippet = (text: string, phrase: string) => {
    const idx = text.indexOf(phrase);
    if (idx === -1) return text;
    return (
      <>
        {idx > 0 && <span>{text.slice(0, idx)}</span>}
        <mark className="bg-[rgba(222,192,125,0.7)] text-[#211804] rounded px-0.5">
          {phrase}
        </mark>
        {idx + phrase.length < text.length && (
          <span>{text.slice(idx + phrase.length)}</span>
        )}
      </>
    );
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 15 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className="babel-card p-5"
    >
      <div className="flex items-start justify-between gap-3 mb-3">
        <div>
          <span className="text-[var(--gold-bright)] font-semibold text-sm">
            Вариант {result.variant}
          </span>
          <span className="text-muted-foreground text-xs ml-3">
            позиция {result.position + 1}
          </span>
        </div>
        <Badge
          variant="outline"
          className="border-[rgba(222,192,125,0.3)] text-[var(--gold)] text-xs"
        >
          {ALG.pageLength} символов
        </Badge>
      </div>

      {/* Snippet */}
      <p className="text-sm text-muted-foreground mb-3 leading-relaxed font-mono">
        {highlightSnippet(result.snippet, result.phrase)}
      </p>

      {/* Coordinates */}
      <div className="rounded-lg border border-[rgba(222,192,125,0.2)] bg-[rgba(222,192,125,0.06)] p-3 mb-3">
        <p className="text-xs text-muted-foreground mb-1.5">Координаты</p>
        <div className="flex flex-wrap gap-1.5">
          {[
            { label: "sector", value: shortNumber(c.sector) },
            { label: "hall", value: String(c.hall) },
            { label: "wall", value: String(c.wall) },
            { label: "shelf", value: String(c.shelf) },
            { label: "volume", value: String(c.volume) },
            { label: "page", value: String(c.page) },
          ].map((item) => (
            <span
              key={item.label}
              className="inline-flex items-center rounded-lg border border-[rgba(255,255,255,0.12)] bg-[rgba(0,0,0,0.22)] px-2 py-1 text-xs mono-text"
            >
              {item.label} {item.value}
            </span>
          ))}
        </div>
        <p className="text-xs text-muted-foreground mt-2">base64url</p>
        <p className="mono-text text-xs mt-0.5 break-all">
          {result.b64.length > 120 ? result.b64.slice(0, 120) + "…" : result.b64}
        </p>
      </div>

      {/* Actions */}
      <div className="flex flex-wrap gap-2">
        <Button
          size="sm"
          onClick={onOpen}
          className="bg-[rgba(222,192,125,0.2)] text-[var(--gold-bright)] border border-[rgba(222,192,125,0.48)] hover:bg-[rgba(222,192,125,0.3)]"
        >
          Открыть страницу
        </Button>
        <Button
          variant="ghost"
          size="sm"
          onClick={onCopyB64}
          className="text-muted-foreground hover:text-foreground"
        >
          <Copy className="h-3.5 w-3.5 mr-1" />
          base64url
        </Button>
        <Button
          variant="ghost"
          size="sm"
          onClick={onSave}
          className="text-muted-foreground hover:text-foreground"
        >
          <BookmarkPlus className="h-3.5 w-3.5 mr-1" />
          Сохранить
        </Button>
      </div>
    </motion.div>
  );
}
