"use client";

import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import { useBabelStore } from "@/lib/store";
import {
  numberToText,
  numberToCoordinates,
  textToNumber,
  b64ToNumber,
  base36ToBigInt,
  bigintToBase36,
  maxPageNumber,
  numberToB64,
  prettyBase36,
  coordinateTitleShort,
  shortNumber,
  paragraphize,
  coordinatesToNumber,
  ALG,
} from "@/lib/babel";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ChevronLeft, ChevronRight, Copy, BookmarkPlus, Download, CheckCircle } from "lucide-react";
import { toast } from "sonner";

export function PageView() {
  const {
    currentPageNumber,
    currentHighlight,
    openPage,
    openBrowse,
    addFavorite,
    setView,
  } = useBabelStore();

  const [showPassport, setShowPassport] = useState(false);

  const data = useMemo(() => {
    if (currentPageNumber === null) return null;
    try {
      const n = currentPageNumber;
      const text = numberToText(n);
      const c = numberToCoordinates(n);
      const b64 = numberToB64(n);
      const b36 = prettyBase36(n);
      const titleShort = coordinateTitleShort(c);
      return { n, text, c, b64, b36, titleShort };
    } catch {
      return null;
    }
  }, [currentPageNumber]);

  if (!data) {
    return (
      <div className="relative z-10 max-w-4xl mx-auto px-4 py-6 text-center">
        <p className="text-muted-foreground">Страница не найдена</p>
        <Button onClick={() => setView("landing")} className="mt-4">
          На главную
        </Button>
      </div>
    );
  }

  const { n, text, c, b64, b36, titleShort } = data;

  const handlePrev = () => {
    if (n > 0n) openPage(n - 1n);
    else openPage(maxPageNumber() - 1n);
  };

  const handleNext = () => {
    openPage((n + 1n) % maxPageNumber());
  };

  const handleCopyB64 = () => {
    navigator.clipboard.writeText(b64);
    toast.success("base64url скопирован");
  };

  const handleCopyCoord = () => {
    const coordStr = `sector ${c.sector} / hall ${c.hall} / wall ${c.wall} / shelf ${c.shelf} / volume ${c.volume} / page ${c.page}`;
    navigator.clipboard.writeText(coordStr);
    toast.success("Координаты скопированы");
  };

  const handleCopyText = () => {
    navigator.clipboard.writeText(text);
    toast.success("Текст скопирован");
  };

  const handleSave = () => {
    addFavorite({ title: titleShort, n: n.toString(), type: "page" });
    toast.success("Добавлено в избранное");
  };

  const handleDownload = () => {
    const blob = new Blob(
      [
        `${titleShort}\n\n${text}\n\nКоординаты:\nsector ${c.sector} / hall ${c.hall} / wall ${c.wall} / shelf ${c.shelf} / volume ${c.volume} / page ${c.page}\n\nbase64url:\n${b64}\n`,
      ],
      { type: "text/plain;charset=utf-8" }
    );
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = "babel-page.txt";
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleSelfTest = () => {
    try {
      const againN = textToNumber(text);
      const from64 = b64ToNumber(numberToB64(n));
      const from36 = base36ToBigInt(bigintToBase36(n));
      const coordN = coordinatesToNumber(c);
      const ok = againN === n && from64 === n && from36 === n && coordN === n;
      toast[ok ? "success" : "error"](
        ok
          ? "Самопроверка пройдена: координаты, текст, base36/base64url согласованы."
          : "Самопроверка не пройдена."
      );
    } catch {
      toast.error("Ошибка самопроверки");
    }
  };

  // Render page text with highlight
  const renderText = () => {
    const para = paragraphize(text);
    const lines = para.split("\n");

    if (!currentHighlight) {
      return <pre className="whitespace-pre-wrap">{para}</pre>;
    }

    // Map highlight position to line/char position
    let charCount = 0;
    const elements: React.ReactNode[] = [];

    for (let lineIdx = 0; lineIdx < lines.length; lineIdx++) {
      const line = lines[lineIdx];
      for (let charIdx = 0; charIdx < line.length; charIdx++) {
        const globalPos = charCount;
        const isHighlighted =
          currentHighlight &&
          globalPos >= currentHighlight.start &&
          globalPos < currentHighlight.start + currentHighlight.length;

        if (isHighlighted) {
          elements.push(
            <span key={`${lineIdx}-${charIdx}`} className="char-marked">
              {line[charIdx]}
            </span>
          );
        } else {
          elements.push(
            <span key={`${lineIdx}-${charIdx}`}>{line[charIdx]}</span>
          );
        }
        charCount++;
      }
      if (lineIdx < lines.length - 1) {
        elements.push(<br key={`br-${lineIdx}`} />);
        charCount++; // for the newline
      }
    }

    return <>{elements}</>;
  };

  return (
    <div className="relative z-10 max-w-4xl mx-auto px-4 py-6">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        {/* Breadcrumbs */}
        <div className="flex flex-wrap gap-2 mb-4">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => openBrowse(c, "hall")}
            className="text-muted-foreground hover:text-foreground text-xs h-7"
          >
            Сектор {shortNumber(c.sector)} · Зал {c.hall}
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => openBrowse(c, "wall")}
            className="text-muted-foreground hover:text-foreground text-xs h-7"
          >
            Стена {c.wall}
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => openBrowse(c, "shelf")}
            className="text-muted-foreground hover:text-foreground text-xs h-7"
          >
            Полка {c.shelf}
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => openBrowse(c, "volume")}
            className="text-muted-foreground hover:text-foreground text-xs h-7"
          >
            Том {c.volume}
          </Button>
          <span className="text-[var(--gold-bright)] text-xs flex items-center font-medium">
            Лист {c.page}
          </span>
        </div>

        {/* Title */}
        <h1 className="text-xl sm:text-2xl md:text-3xl font-bold text-foreground mb-4 break-words">
          {titleShort}
        </h1>

        {/* Page navigation */}
        <div className="flex justify-center gap-3 mb-4">
          <Button
            variant="ghost"
            size="sm"
            onClick={handlePrev}
            className="text-muted-foreground hover:text-foreground"
          >
            <ChevronLeft className="h-4 w-4 mr-1" />
            Пред. страница
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleNext}
            className="text-muted-foreground hover:text-foreground"
          >
            След. страница
            <ChevronRight className="h-4 w-4 ml-1" />
          </Button>
        </div>

        {/* Page text */}
        <div className="page-text mb-4">{renderText()}</div>

        {/* Badges */}
        <div className="flex flex-wrap gap-2 mb-4">
          <Badge variant="outline" className="border-border text-muted-foreground">
            ru1
          </Badge>
          <Badge variant="outline" className="border-border text-muted-foreground">
            координаты реальные
          </Badge>
          <Badge variant="outline" className="border-border text-muted-foreground">
            {ALG.pageLength} символов
          </Badge>
          <Badge variant="outline" className="border-border text-muted-foreground">
            алфавит {ALG.alphabet.length}
          </Badge>
        </div>

        {/* Navigation actions */}
        <div className="babel-card p-4 mb-4">
          <p className="text-xs text-muted-foreground mb-2 font-medium">Навигация</p>
          <div className="flex flex-wrap gap-2">
            <Button variant="ghost" size="sm" onClick={() => openBrowse(c, "volume")} className="text-muted-foreground hover:text-foreground">
              Том
            </Button>
            <Button variant="ghost" size="sm" onClick={() => openBrowse(c, "shelf")} className="text-muted-foreground hover:text-foreground">
              Полка
            </Button>
            <Button variant="ghost" size="sm" onClick={() => openBrowse(c, "wall")} className="text-muted-foreground hover:text-foreground">
              Стена
            </Button>
            <Button variant="ghost" size="sm" onClick={() => openBrowse(c, "hall")} className="text-muted-foreground hover:text-foreground">
              Зал
            </Button>
          </div>
        </div>

        {/* Actions */}
        <div className="babel-card p-4 mb-4">
          <p className="text-xs text-muted-foreground mb-2 font-medium">Действия</p>
          <div className="flex flex-wrap gap-2">
            <Button variant="ghost" size="sm" onClick={handleCopyCoord} className="text-muted-foreground hover:text-foreground">
              <Copy className="h-3.5 w-3.5 mr-1" />
              Координаты
            </Button>
            <Button variant="ghost" size="sm" onClick={handleCopyB64} className="text-muted-foreground hover:text-foreground">
              <Copy className="h-3.5 w-3.5 mr-1" />
              base64url
            </Button>
            <Button variant="ghost" size="sm" onClick={handleCopyText} className="text-muted-foreground hover:text-foreground">
              <Copy className="h-3.5 w-3.5 mr-1" />
              Текст
            </Button>
            <Button variant="ghost" size="sm" onClick={handleSave} className="text-muted-foreground hover:text-foreground">
              <BookmarkPlus className="h-3.5 w-3.5 mr-1" />
              В избранное
            </Button>
            <Button variant="ghost" size="sm" onClick={handleDownload} className="text-muted-foreground hover:text-foreground">
              <Download className="h-3.5 w-3.5 mr-1" />
              Скачать .txt
            </Button>
            <Button variant="ghost" size="sm" onClick={handleSelfTest} className="text-muted-foreground hover:text-foreground">
              <CheckCircle className="h-3.5 w-3.5 mr-1" />
              Самопроверка
            </Button>
          </div>
        </div>

        {/* Passport (collapsible) */}
        <details
          open={showPassport}
          onToggle={(e) => setShowPassport((e.target as HTMLDetailsElement).open)}
          className="mb-4"
        >
          <summary className="w-full babel-card p-4 text-left flex items-center justify-between cursor-pointer hover:border-[rgba(222,192,125,0.3)] transition-colors list-none">
            <span className="text-[var(--gold-bright)] font-semibold text-sm">
              Паспорт страницы
            </span>
            <ChevronRight
              className={`h-4 w-4 text-muted-foreground transition-transform duration-200 ${showPassport ? "rotate-90" : ""}`}
            />
          </summary>
          <div className="babel-card p-4 mt-2">
            <div className="grid grid-cols-[auto_1fr] gap-x-4 gap-y-2 text-sm">
              <span className="text-muted-foreground">Координаты</span>
              <span className="mono-text text-xs break-all">
                sector {shortNumber(c.sector)} / hall {c.hall} / wall {c.wall} / shelf {c.shelf} / volume {c.volume} / page {c.page}
              </span>

              <span className="text-muted-foreground">base64url</span>
              <span className="mono-text text-xs break-all">
                {b64.length > 120 ? b64.slice(0, 120) + "…" : b64}
              </span>

              <span className="text-muted-foreground">base36</span>
              <span className="mono-text text-xs break-all">
                {b36.length > 96 ? b36.slice(0, 96) + "…" : b36}
              </span>

              <span className="text-muted-foreground">BigInt</span>
              <span className="mono-text text-xs break-all">
                {n.toString().length > 80 ? n.toString().slice(0, 80) + "…" : n.toString()}
              </span>
            </div>
          </div>
        </details>
      </motion.div>
    </div>
  );
}
