"use client";

import { useMemo } from "react";
import { motion } from "framer-motion";
import { useBabelStore } from "@/lib/store";
import {
  Coordinates,
  coordinatesToNumber,
  shortNumber,
  ALG,
} from "@/lib/babel";
import { Button } from "@/components/ui/button";
import {
  ArrowLeft,
  Hexagon,
  BookOpen,
} from "lucide-react";

export function BrowseView() {
  const { browseCoordinates, browseLevel, openBrowse, openPage, setView } = useBabelStore();

  if (!browseCoordinates || !browseLevel) {
    return (
      <div className="relative z-10 max-w-4xl mx-auto px-4 py-6 text-center">
        <p className="text-muted-foreground mb-4">Выберите начальную точку навигации</p>
        <Button
          onClick={() =>
            openBrowse(
              { sector: 1n, hall: 1n, wall: 1n, shelf: 1n, volume: 1n, page: 1n },
              "hall"
            )
          }
          className="bg-[rgba(222,192,125,0.2)] text-[var(--gold-bright)] border border-[rgba(222,192,125,0.48)]"
        >
          Начать с первого зала
        </Button>
      </div>
    );
  }

  return (
    <div className="relative z-10 max-w-4xl mx-auto px-4 py-6">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        {/* Back button */}
        <Button
          variant="ghost"
          size="sm"
          onClick={() => setView("landing")}
          className="text-muted-foreground hover:text-foreground mb-4"
        >
          <ArrowLeft className="h-4 w-4 mr-1" />
          На главную
        </Button>

        {browseLevel === "hall" && <HallView c={browseCoordinates} />}
        {browseLevel === "wall" && <WallView c={browseCoordinates} />}
        {browseLevel === "shelf" && <ShelfView c={browseCoordinates} />}
        {browseLevel === "volume" && <VolumeView c={browseCoordinates} />}
      </motion.div>
    </div>
  );
}

function BreadcrumbNav({ c, level }: { c: Coordinates; level: string }) {
  const { openBrowse } = useBabelStore();
  const items = [
    {
      label: `Сектор ${shortNumber(c.sector)} · Зал ${c.hall}`,
      onClick: () => openBrowse(c, "hall"),
      active: level === "hall",
    },
    {
      label: `Стена ${c.wall}`,
      onClick: () => openBrowse(c, "wall"),
      active: level === "wall",
    },
    {
      label: `Полка ${c.shelf}`,
      onClick: () => openBrowse(c, "shelf"),
      active: level === "shelf",
    },
    {
      label: `Том ${c.volume}`,
      onClick: () => openBrowse(c, "volume"),
      active: level === "volume",
    },
  ];

  return (
    <div className="flex flex-wrap gap-2 mb-6">
      {items.map((item, idx) => (
        <button
          key={idx}
          onClick={item.onClick}
          className={`text-xs px-3 py-1.5 rounded-lg border transition-colors cursor-pointer ${
            item.active
              ? "border-[rgba(222,192,125,0.48)] bg-[rgba(222,192,125,0.13)] text-[var(--gold-bright)]"
              : "border-border text-muted-foreground hover:text-foreground hover:bg-[rgba(255,255,255,0.05)]"
          }`}
        >
          {item.label}
        </button>
      ))}
    </div>
  );
}

function HallView({ c }: { c: Coordinates }) {
  const { openBrowse } = useBabelStore();

  return (
    <>
      <h1 className="text-2xl sm:text-3xl font-bold text-[var(--gold-bright)] mb-2">
        Сектор {shortNumber(c.sector)} · Зал {c.hall}
      </h1>
      <p className="text-muted-foreground text-sm mb-6">
        Шестигранный зал с 4 стенами, на каждой — 5 полок
      </p>

      {/* Hexagonal layout */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {Array.from({ length: Number(ALG.wallsPerHall) }, (_, i) => {
          const w = BigInt(i + 1);
          const wallC: Coordinates = {
            ...c,
            wall: w,
            shelf: 1n,
            volume: 1n,
            page: 1n,
          };
          return (
            <motion.button
              key={i}
              whileHover={{ scale: 1.03 }}
              whileTap={{ scale: 0.97 }}
              onClick={() => openBrowse(wallC, "wall")}
              className="babel-card p-5 text-center transition-all hover:border-[rgba(222,192,125,0.48)] hover:shadow-[0_0_20px_rgba(222,192,125,0.1)] cursor-pointer"
            >
              <Hexagon className="h-10 w-10 mx-auto mb-3 text-[var(--gold)] opacity-60" />
              <p className="text-[var(--gold-bright)] font-semibold">
                Стена {w}
              </p>
              <p className="text-muted-foreground text-xs mt-1">
                {ALG.shelvesPerWall} полок
              </p>
            </motion.button>
          );
        })}
      </div>
    </>
  );
}

function WallView({ c }: { c: Coordinates }) {
  const { openBrowse } = useBabelStore();

  return (
    <>
      <BreadcrumbNav c={c} level="wall" />
      <h1 className="text-2xl sm:text-3xl font-bold text-[var(--gold-bright)] mb-2">
        Стена {c.wall}
      </h1>
      <p className="text-muted-foreground text-sm mb-6">
        5 полок, на каждой — 32 тома
      </p>

      <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-5 gap-4">
        {Array.from({ length: Number(ALG.shelvesPerWall) }, (_, i) => {
          const s = BigInt(i + 1);
          const shelfC: Coordinates = {
            ...c,
            shelf: s,
            volume: 1n,
            page: 1n,
          };
          return (
            <motion.button
              key={i}
              whileHover={{ scale: 1.03 }}
              whileTap={{ scale: 0.97 }}
              onClick={() => openBrowse(shelfC, "shelf")}
              className="babel-card p-4 text-center transition-all hover:border-[rgba(222,192,125,0.48)] hover:shadow-[0_0_20px_rgba(222,192,125,0.1)] cursor-pointer"
            >
              <p className="text-[var(--gold-bright)] font-semibold">
                Полка {s}
              </p>
              <p className="text-muted-foreground text-xs mt-1">
                {ALG.volumesPerShelf} тома
              </p>
            </motion.button>
          );
        })}
      </div>
    </>
  );
}

function ShelfView({ c }: { c: Coordinates }) {
  const { openBrowse } = useBabelStore();

  return (
    <>
      <BreadcrumbNav c={c} level="shelf" />
      <h1 className="text-2xl sm:text-3xl font-bold text-[var(--gold-bright)] mb-2">
        Полка {c.shelf}
      </h1>
      <p className="text-muted-foreground text-sm mb-6">
        32 тома, в каждом — 410 страниц
      </p>

      <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-8 gap-3">
        {Array.from({ length: Number(ALG.volumesPerShelf) }, (_, i) => {
          const v = BigInt(i + 1);
          const volC: Coordinates = {
            ...c,
            volume: v,
            page: 1n,
          };
          return (
            <motion.button
              key={i}
              whileHover={{ scale: 1.03 }}
              whileTap={{ scale: 0.97 }}
              onClick={() => openBrowse(volC, "volume")}
              className="babel-card p-3 text-center transition-all hover:border-[rgba(222,192,125,0.48)] cursor-pointer"
            >
              <BookOpen className="h-5 w-5 mx-auto mb-1.5 text-[var(--gold)] opacity-60" />
              <p className="text-[var(--gold-bright)] font-medium text-sm">
                Том {v}
              </p>
              <p className="text-muted-foreground text-xs">
                {ALG.pagesPerVolume} стр.
              </p>
            </motion.button>
          );
        })}
      </div>
    </>
  );
}

function VolumeView({ c }: { c: Coordinates }) {
  const { openPage } = useBabelStore();

  // Show pages in a grid
  const pages = useMemo(() => {
    return Array.from({ length: Number(ALG.pagesPerVolume) }, (_, i) => {
      const pg = BigInt(i + 1);
      const pageC: Coordinates = { ...c, page: pg };
      try {
        const n = coordinatesToNumber(pageC);
        return { idx: i, pg, n, c: pageC };
      } catch {
        return null;
      }
    }).filter(Boolean) as Array<{ idx: number; pg: bigint; n: bigint; c: Coordinates }>;
  }, [c]);

  return (
    <>
      <BreadcrumbNav c={c} level="volume" />
      <h1 className="text-2xl sm:text-3xl font-bold text-[var(--gold-bright)] mb-2">
        Том {c.volume}
      </h1>
      <p className="text-muted-foreground text-sm mb-6">
        410 страниц (листов)
      </p>

      <div className="grid grid-cols-5 sm:grid-cols-10 lg:grid-cols-20 gap-2">
        {pages.map((p) => (
          <motion.button
            key={p.idx}
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => openPage(p.n)}
            className="babel-card p-2 text-center transition-all hover:border-[rgba(222,192,125,0.48)] cursor-pointer"
          >
            <p className="text-[var(--gold-bright)] text-xs font-medium">
              {p.pg}
            </p>
          </motion.button>
        ))}
      </div>
    </>
  );
}
