// Русская Библиотека Вавилона — Core Algorithm
// Ported from the original app.js with TypeScript types

export const VERSION = "ru1";

export const ALG = {
  label: "ru1",
  alphabet: " абвгдеёжзийклмнопрстуфхцчшщъыьэюя.,!?;:—«»()0123456789",
  pageLength: 900,
  lineWidth: 90,
  pagesPerVolume: 410n,
  volumesPerShelf: 32n,
  shelvesPerWall: 5n,
  wallsPerHall: 4n,
  hallsPerSector: 20n,
};

export const DEFAULT_VARIANTS = 8;
export const MAX_VARIANTS = 48;

// --- Hash functions ---

export function fnv1a(str: string): number {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return h >>> 0;
}

export function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

export function rngFrom(text: string): () => number {
  return mulberry32(fnv1a(text));
}

// --- Text operations ---

export function normalizeText(raw: string): string {
  const lower = String(raw || "").toLowerCase().replace(/\s+/g, " ").trim();
  let out = "";
  for (const ch of lower) {
    out += ALG.alphabet.includes(ch) ? ch : " ";
  }
  return out.replace(/\s+/g, " ").trim();
}

export function fixedPageText(text: string): string {
  let s = normalizeText(text);
  if (s.length > ALG.pageLength) s = s.slice(0, ALG.pageLength);
  return s.padEnd(ALG.pageLength, " ");
}

export function paragraphize(text: string): string {
  const clean = String(text).replace(/\s+$/g, "");
  const parts: string[] = [];
  for (let i = 0; i < clean.length; i += ALG.lineWidth) {
    parts.push(clean.slice(i, i + ALG.lineWidth));
  }
  return parts.join("\n");
}

// --- Core conversions ---

export function maxPageNumber(): bigint {
  return BigInt(ALG.alphabet.length) ** BigInt(ALG.pageLength);
}

export function textToNumber(text: string): bigint {
  const base = BigInt(ALG.alphabet.length);
  const fixed = fixedPageText(text);
  let n = 0n;
  for (const ch of fixed) {
    const d = ALG.alphabet.indexOf(ch);
    if (d < 0) throw new Error(`Символ не входит в алфавит: ${ch}`);
    n = n * base + BigInt(d);
  }
  return n;
}

export function numberToText(n: bigint): string {
  const max = maxPageNumber();
  const x = BigInt(n);
  if (x < 0n || x >= max) throw new Error("Адрес вне пространства библиотеки.");
  const base = BigInt(ALG.alphabet.length);
  const chars = new Array<string>(ALG.pageLength);
  let rem = x;
  for (let i = ALG.pageLength - 1; i >= 0; i--) {
    const d = Number(rem % base);
    chars[i] = ALG.alphabet[d];
    rem = rem / base;
  }
  return chars.join("");
}

// --- Coordinate types and conversions ---

export interface Coordinates {
  sector: bigint;
  hall: bigint;
  wall: bigint;
  shelf: bigint;
  volume: bigint;
  page: bigint;
}

export function numberToCoordinates(n: bigint): Coordinates {
  let x = BigInt(n);
  const pg = (x % ALG.pagesPerVolume) + 1n;
  x /= ALG.pagesPerVolume;
  const vol = (x % ALG.volumesPerShelf) + 1n;
  x /= ALG.volumesPerShelf;
  const sh = (x % ALG.shelvesPerWall) + 1n;
  x /= ALG.shelvesPerWall;
  const w = (x % ALG.wallsPerHall) + 1n;
  x /= ALG.wallsPerHall;
  const h = (x % ALG.hallsPerSector) + 1n;
  x /= ALG.hallsPerSector;
  const s = x + 1n;
  return { sector: s, hall: h, wall: w, shelf: sh, volume: vol, page: pg };
}

export function coordinatesToNumber(c: Coordinates): bigint {
  const sector = BigInt(c.sector || 1n);
  const hall = BigInt(c.hall || 1n);
  const wall = BigInt(c.wall || 1n);
  const shelf = BigInt(c.shelf || 1n);
  const volume = BigInt(c.volume || 1n);
  const page = BigInt(c.page || 1n);

  if (
    sector < 1n ||
    hall < 1n ||
    hall > ALG.hallsPerSector ||
    wall < 1n ||
    wall > ALG.wallsPerHall ||
    shelf < 1n ||
    shelf > ALG.shelvesPerWall ||
    volume < 1n ||
    volume > ALG.volumesPerShelf ||
    page < 1n ||
    page > ALG.pagesPerVolume
  ) {
    throw new Error("Координаты вне геометрии библиотеки.");
  }

  let x = sector - 1n;
  x = x * ALG.hallsPerSector + (hall - 1n);
  x = x * ALG.wallsPerHall + (wall - 1n);
  x = x * ALG.shelvesPerWall + (shelf - 1n);
  x = x * ALG.volumesPerShelf + (volume - 1n);
  x = x * ALG.pagesPerVolume + (page - 1n);

  if (x >= maxPageNumber()) {
    throw new Error("Координаты дают число вне пространства страниц.");
  }
  return x;
}

// --- Address formats ---

export function bigintToBase36(n: bigint): string {
  return BigInt(n).toString(36);
}

export function base36ToBigInt(s: string): bigint {
  const clean = String(s || "").toLowerCase().replace(/[^0-9a-z]/g, "");
  if (!clean) return 0n;
  let n = 0n;
  for (const ch of clean) {
    const code = ch.charCodeAt(0);
    let d: number;
    if (code >= 48 && code <= 57) d = code - 48;
    else if (code >= 97 && code <= 122) d = code - 87;
    else continue;
    n = n * 36n + BigInt(d);
  }
  return n;
}

export function bigIntToBytes(n: bigint): Uint8Array {
  let x = BigInt(n);
  if (x === 0n) return new Uint8Array([0]);
  const arr: number[] = [];
  while (x > 0n) {
    arr.push(Number(x & 255n));
    x >>= 8n;
  }
  return Uint8Array.from(arr.reverse());
}

export function bytesToBigInt(bytes: Uint8Array): bigint {
  let n = 0n;
  for (const b of bytes) {
    n = (n << 8n) + BigInt(b);
  }
  return n;
}

export function bytesToBase64Url(bytes: Uint8Array): string {
  let bin = "";
  for (const b of bytes) bin += String.fromCharCode(b);
  return btoa(bin).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

export function base64UrlToBytes(s: string): Uint8Array {
  const base = String(s || "").replace(/-/g, "+").replace(/_/g, "/");
  const padded = base + "=".repeat(((4 - (base.length % 4)) % 4));
  const bin = atob(padded);
  return Uint8Array.from([...bin].map((ch) => ch.charCodeAt(0)));
}

export function numberToB64(n: bigint): string {
  return bytesToBase64Url(bigIntToBytes(n));
}

export function b64ToNumber(s: string): bigint {
  return bytesToBigInt(base64UrlToBytes(s));
}

export function prettyBase36(n: bigint): string {
  const clean = bigintToBase36(n);
  const chunks: string[] = [];
  for (let i = 0; i < clean.length; i += 8) {
    chunks.push(clean.slice(i, i + 8));
  }
  return chunks.join("-");
}

// --- Coordinate display helpers ---

export function shortNumber(value: bigint | string): string {
  const s = String(value);
  if (s.length <= 12) return s;
  return `${s.slice(0, 6)}…${s.slice(-4)}`;
}

export function coordinateTitle(c: Coordinates): string {
  return `Сектор ${c.sector} · Зал ${c.hall} · Стена ${c.wall} · Полка ${c.shelf} · Том ${c.volume} · Лист ${c.page}`;
}

export function coordinateTitleShort(c: Coordinates): string {
  return `Стена ${c.wall} · Полка ${c.shelf} · Том ${c.volume} · Лист ${c.page}`;
}

// --- Page generation ---

export function randomPageText(): string {
  const rng = rngFrom(`${Date.now()}:${Math.random()}`);
  let s = "";
  for (let i = 0; i < ALG.pageLength; i++) {
    s += ALG.alphabet[Math.floor(rng() * ALG.alphabet.length)];
  }
  return s;
}

export type Strategy = "random" | "quiet" | "center" | "start" | "end" | "emptiness";

export interface PageWithPhrase {
  phrase: string;
  variant: number;
  position: number;
  text: string;
}

export function makePageWithPhrase(
  phraseRaw: string,
  variant: number,
  strategy: Strategy,
  offset = 0
): PageWithPhrase {
  const phrase = normalizeText(phraseRaw);
  if (!phrase) throw new Error("После нормализации фраза пустая.");
  if (phrase.length > ALG.pageLength)
    throw new Error(
      `Фраза длиннее страницы: ${phrase.length} символов при лимите ${ALG.pageLength}.`
    );

  const variantNumber = offset + variant;
  const rng = rngFrom(
    `${VERSION}:phrase:${phrase}:variant:${variantNumber}:strategy:${strategy}`
  );
  const chars = new Array<string>(ALG.pageLength);

  // Fill with random characters (default for "random" and "chaos")
  for (let i = 0; i < ALG.pageLength; i++) {
    chars[i] = ALG.alphabet[Math.floor(rng() * ALG.alphabet.length)];
  }

  // "quiet" / "center": ~18% spaces → resembles words
  if (strategy === "quiet" || strategy === "center") {
    for (let i = 0; i < ALG.pageLength; i++) {
      if (rng() < 0.18) chars[i] = " ";
    }
  }

  // "emptiness": fill everything with spaces
  if (strategy === "emptiness") {
    for (let i = 0; i < ALG.pageLength; i++) {
      chars[i] = " ";
    }
  }

  // Determine position
  const maxPos = ALG.pageLength - phrase.length;
  let position: number;

  if (strategy === "start") position = Math.min(24, maxPos);
  else if (strategy === "end") position = Math.max(0, maxPos - 24);
  else if (strategy === "center")
    position = Math.max(0, Math.floor((ALG.pageLength - phrase.length) / 2));
  else position = Math.floor(rng() * (maxPos + 1));

  // Pad phrase with spaces
  if (position > 0) chars[position - 1] = " ";
  for (let i = 0; i < phrase.length; i++) {
    chars[position + i] = phrase[i];
  }
  if (position + phrase.length < chars.length) {
    chars[position + phrase.length] = " ";
  }

  return { phrase, variant: variantNumber, position, text: chars.join("") };
}

// --- Snippet / highlight helpers ---

export function snippetByRange(
  text: string,
  range: { start: number; length: number },
  pad = 80
): string {
  const s = Math.max(0, range.start - pad);
  const e = Math.min(text.length, range.start + range.length + pad);
  return `${s > 0 ? "… " : ""}${text.slice(s, e).trim()}${e < text.length ? " …" : ""}`;
}

// --- Variant type for the new UI ---

export type VariantType = "emptiness" | "chaos" | "words";

export function strategyFromVariantType(
  variantType: VariantType,
  positionStrategy: "center" | "start" | "end" | "random"
): Strategy {
  if (variantType === "emptiness") return "emptiness";
  if (variantType === "words") return "quiet";
  // chaos → random
  if (positionStrategy === "center") return "center";
  if (positionStrategy === "start") return "start";
  if (positionStrategy === "end") return "end";
  return "random";
}

// --- Favorites / History helpers (localStorage) ---

export function getFavorites(): Array<Record<string, string>> {
  try {
    return JSON.parse(localStorage.getItem("babelFavorites") || "[]");
  } catch {
    return [];
  }
}

export function saveFavorites(items: Array<Record<string, string>>): void {
  localStorage.setItem("babelFavorites", JSON.stringify(items.slice(0, 120)));
}

export function addFavorite(item: Record<string, string>): void {
  const key = item.n || item.url;
  const items = getFavorites().filter((x) => (x.n || x.url) !== key);
  items.unshift({ ...item, createdAt: new Date().toISOString() });
  saveFavorites(items);
}

export function removeFavorite(index: number): void {
  const arr = getFavorites();
  arr.splice(index, 1);
  saveFavorites(arr);
}

export function getHistory(): Array<Record<string, string>> {
  try {
    return JSON.parse(localStorage.getItem("babelHistory") || "[]");
  } catch {
    return [];
  }
}

export function pushHistory(item: Record<string, string>): void {
  const items = getHistory().filter((x) => x.url !== item.url);
  items.unshift({ ...item, createdAt: new Date().toISOString() });
  localStorage.setItem("babelHistory", JSON.stringify(items.slice(0, 100)));
}
